Here's a modern MSTest approach using `HttpMessageHandler` mocking, async test methods, and cancellation testing:

```csharp
using System.Net;
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)] // Fails test if it hangs longer than 5s
    public async Task FetchAsync_HonoursCancellationToken()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // Pre-cancel

        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("data")
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancelsDuringRequest()
    {
        using var cts = new CancellationTokenSource();
        var handler = new DelayedHandler(cts); // Cancels mid-flight
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler for deterministic tests
    private class FakeHandler(HttpResponseMessage response) : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(response);
        }
    }

    // Simulates a slow request that gets cancelled mid-flight
    private class DelayedHandler(CancellationTokenSource cts) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cts.CancelAfter(50);
            await Task.Delay(10_000, cancellationToken);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| Async tests | `async Task` return type — MSTest awaits them natively |
| Timeouts | `[Timeout(ms)]` attribute prevents hangs in CI |
| Cancellation | Pre-cancelled token + mid-flight cancellation via `CancellationTokenSource` |
| No external mocking lib | Custom `HttpMessageHandler` keeps tests dependency-free |

**Tips:**
- Always use `[Timeout]` on async tests to catch deadlocks.
- Test both pre-cancelled and mid-request cancellation scenarios.
- `Assert.ThrowsExceptionAsync` is the async counterpart — never use `.Result` or `.Wait()` in async tests.
